INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-57f41407-moex-00326', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「坊間攝影書，最常提到的關鍵字不外乎是：景深、快門、光圈，種種競 選口號般速成式的激情，但我相信唯有勇氣、體貼與好奇，才能讓攝影與 生活產生更緊密的聯繫，我們似乎總是忘記，拍照最常用到的其實不是單 眼相機，是你的那雙眼睛。」 根據上文，下列選項何者最符合文意？', '["攝影書常為求速成而內容不實", "攝影要能等待時機、掌握變化", "具備審美的眼光就能拍出好照片", "養成攝影之眼需要細膩觀察生活"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00327', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「臺灣人許多時候將『飲食』視為社交活動，對食物很疏離，只對入口的 東西有慾望，但對食品產業結構、到身體產生什麼變化，不太關心，而且 過度追求『便宜大碗』的氛圍下，忽略食材、人工成本，廠商於是拚命壓 低成本，甚至走上偏路，消費者成了不健康競爭的間接推手。『不把態度 擺正，再多規範、溯源，都可以破解』，若要建立美食王國聲譽，臺灣消 費者可以做得更多。 」 根據上文，下列選項最符合文意的是：', '["食品法規無助於食品安全，消費者必須謹慎挑選", "廠商拚命壓低成本，以薄利多銷手法衝刺市占率", "消費者有健全的飲食態度，才能從源頭強化食安", "社會的停滯性通膨，導致消費者追求便宜又大碗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00328', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「人在工作時，由於精神專注，意志集中，自能煥發出生命的光芒；在無 所事事時，人立即顯得無精打采，悵然若失，既看不到眼神中激昂的鬥志， 動作中的意氣風發也頹然若止。」 下列選項，最合乎本文意旨的是：', '["精神專注可提升工作效率", "人在專心工作時最具光彩", "工作讓人年輕且活得充實", "離開工作會讓人獲得自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00329', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「弓頭鯨的名稱得自巨大而獨特的弓狀頭顱。其軀體非常沉重，雖然至今 還未曾整個或局部地被秤過，一般相信就其體長來看，應該比其他的鯨都 重。經常與一角鯨、白鯨結伴，是生活在北極的唯一大型鯨類動物。鯨脂 厚達70公分，有助其禦寒；能穿破厚達30公分的冰層，為自己開鑿呼吸 孔。有顯著的白色下巴，身上沒有皮繭，也沒有背鰭，這些特徵應足以用 來辨認。」 根據上文，下列選項正確的是：', '["弓頭鯨之名來自其弓狀的頭顱，可能是世界上最長的鯨豚", "弓頭鯨、一角鯨、白鯨，都是棲息於北極的大型鯨類動物", "弓頭鯨擁有厚重的脂肪，主要功能在於抵禦棲地嚴酷的低溫", "弓頭鯨全身呈現黑色、藍黑色，但只有胸鰭和尾鰭是深褐色"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00330', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「迷迭香具有殺菌、消毒、防蟲的功效，在無法用科學證實迷迭香效用的 年代裡，古時候的人相信迷迭香可以驅魔。因為迷迭香的味道與香氣過於 濃郁，拿來料理時要特別注意分量。大部分料理方式是將新鮮的迷迭香鋪 在羊肉下面，或塞進雞或魚的肚裡，再放入烤箱。另外，葉子也可以加進 番茄湯裡熬煮，製作餅乾、麵包時也常會加入迷迭香。」 根據上文，關於迷迭香的敘述，下列選項何者正確？', '["用途不限於料理", "葉子不適合食用", "口味溫和，煮菜時多多益善", "只能用於肉類料理，如羊、雞、魚等"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00331', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「金融風暴之後，世界恐慌已湧向職場，倒閉嚴重，沒倒的公司裡也潛在 著失業危機。與其當機不動，還不如積極培養自己的品牌力，人脈關係， 做好相關市場調查，啟動腦中的偵測天線，早日重新開機，而重新開機前， 心理上不要在乎升官速度變慢。」 下列選項，最符合上文旨趣的是：', '["適時關機，如同休息為了走更長的路", "金融危機可能讓頭腦當機，無法適應", "不畏環境變數，累積自己實力方為上策", "思考升官速度快慢，不如避免金融危機"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00332', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「網路搜尋能提升人們的『認知自尊』，即對於自身記性和處理資訊能力 的感受往往自我感覺良好，時常搞混自己與別人擁有的知識。問題在於， 花個幾小時仔細瀏覽醫學網站，不可能取代多年訓練培育出來的專業，以 及據此做出的合格醫療診斷。醫療專業人員表示，做過網路搜尋的病患知 道的資訊跟沒查網路的病患差不多。然而，他們卻容易對自己的醫療知識 很有信心，進而造成不相信專業人員的診斷，或寧願尋求另類療法。」 下列選項，何者最符合本文意旨？', '["自我感覺良好者易錯判情勢而危及生命", "醫療專業高深，但是未必勝過另類療法", "知識取得容易，讓人產生無所不知的錯覺", "網路資訊破碎，實際上無助於問題的解決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00333', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「從月鳳和我的演講之後，班上又加了一種讀書方法——演說。人人爭著 說。我們打招呼、看衣服、讀文法、塗漫畫、改小說、吃糖果、切蛋糕、 泡茶水，然後一國一國的文化開始上演。那教室，像極了一座流動的旋轉 馬。每一個人騎在一匹響著音樂的馬上，高高低低的旋轉不停。」 根據上文，下列選項最接近教室學習氣氛的描述是：', '["多元學習樂無窮", "循序漸進效率高", "各憑本事爭出頭", "獨善其身做學問"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00334', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「蛋餅總是連結著我每一天生產力的開端，從前連結上學，後來連結上班。 粉漿蛋餅登場的時候，是我成年的開始，學校裡有聰慧的老師，有知心的 同學，有戀慕的對象，面對模糊的未來卻懷抱著明確的希望。後來再吃到 的蛋餅，連結遲到一分鐘扣五十元的打卡，還有輸入整頁資料卻當機的電 腦視窗。」 根據上文，下列選項對於蛋餅滋味的敘述何者正確？', '["不同的蛋餅卻有相似的滋味", "來自於人生不同階段的體悟", "從青春到成年的豐富與飽足感", "表達人生無常的循環與宿命感"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00335', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「『指南』激不激發『欲遊者』之夢？若然，那指南豈不如同扣人心弦的 散文或遊記？是的，好的指南常是好的散文寫作，但不多。有的指南，太 感情用事，作者自己沉醉其所旅遊之地，說得天花亂墜，而展書者越讀越 生疑懼，這樣的指南，亦不成功。這樣的書，像是描寫天堂。」 根據上文，最符合本文旨趣的是：', '["好的旅遊指南應吸引人，但是也要顧及真實面向", "旅遊指南不能理性書寫，將使內容流於矯情浮濫", "旅遊指南與旅行文學的差異在於前者更強調客觀", "有主見的旅者非但不依旅遊指南甚至更擅於質疑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
